In Godot Engine 3.x, you can create a first-person controller script using GDScript and apply it to a `KinematicBody` node. Here's a simple example of how you can write such a script:

```gdscript
extends KinematicBody

export var camera_speed : float = 5.0
export var movement_speed : float = 3.0

var velocity = Vector3()
var camera_rotation_y = 0.0

func _physics_process(delta: float):
    var input_vector = Vector3.ZERO

    if Input.is_action_pressed("move_forward"):
        input_vector += transform.basis.z
    if Input.is_action_pressed("move_backward"):
        input_vector -= transform.basis.z
    if Input.is_action_pressed("move_left"):
        input_vector -= transform.basis.x
    if Input.is_action_pressed("move_right"):
        input_vector += transform.basis.x

    velocity.x = input_vector.x * movement_speed
    velocity.z = input_vector.z * movement_speed

    if Input.is_action_pressed("turn_left"):
        camera_rotation_y += 1.0
    if Input.is_action_pressed("turn_right"):
        camera_rotation_y -= 1.0

    velocity = get_global_transform().basis.xform(velocity)
    velocity = move_and_slide(velocity, Vector3.UP, true, 1.0, false)

    # Update camera rotation
    var rot_degrees = camera_rotation_y * 5.0
    var rot_radians = deg2rad(rot_degrees)
    var current_rotation = get_rotation()
    current_rotation.y += rot_radians
    set_rotation(current_rotation)
```

